cps-001.implementationNotes:
# Step 1: Create DLP policy blocking unauthenticated chat connector
# Power Platform admin center > Security > Data policy
# Block: "Chat without Microsoft Entra ID authentication in Copilot Studio"

# Step 2: Scope to all environments (including Default)
# Step 3: Configure DLP error message with contact and policy URL
Add-PowerAppsAccount
New-PowerAppDlpErrorSettings -TenantId "<id>" -ErrorSettings @{
  ContactDetails=@{Enabled=$true;Email="security@contoso.com"}
  ErrorMessageDetails=@{Enabled=$true;Url="https://contoso.sharepoint.com/policy"}
}

# Step 4: Verify — agents with "No authentication" cannot be published

cps-002.implementationNotes:
# Step 1: Restrict environment creation to admins
Add-PowerAppsAccount
Set-TenantSettings -RequestBody @{
  powerPlatform=@{governance=@{disableEnvironmentCreationByNonAdminUsers=$true}}
}

# Step 2: Enable Managed Environments for production
# Step 3: Configure environment routing from Default
# Step 4: Assign security groups per environment
# Step 5: Disable generative AI agent publishing tenant-wide
# Step 6: Set maker welcome message with compliance requirements
